PROCEDURE Encapsulate(data, destIP, destPort)
BEGIN
 // Application Layer
 appData = data

 // Transport Layer - Add segment header
 segment = CREATE_SEGMENT(appData, destPort)

 // Network Layer - Add packet header
 packet = CREATE_PACKET(segment, destIP)

 // Data Link Layer - Add frame header and trailer
 frame = CREATE_FRAME(packet, destMAC)

 // Physical Layer - Convert to bits
 bits = CONVERT_TO_BITS(frame)

 TRANSMIT(bits)
 RETURN bits
END
